import{_ as a,c as r,o as t,ah as s}from"./chunks/framework.DNBwxV9x.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"beginners-guide.md","filePath":"beginners-guide.md"}'),o={name:"beginners-guide.md"};function n(i,e,l,d,c,p){return t(),r("div",null,[...e[0]||(e[0]=[s('<h3 id="basic-guide-about-privacy-and-staying-safe-online" tabindex="-1">Basic guide about privacy and staying safe online <a class="header-anchor" href="#basic-guide-about-privacy-and-staying-safe-online" aria-label="Permalink to “Basic guide about privacy and staying safe online”">​</a></h3><details class="details custom-block"><summary>How to Activate Windows/Office? 🪟</summary><p>Click <a href="https://massgrave.dev/#how-to-activate-windows--office" target="_blank" rel="noreferrer">here</a> for activation</p></details><details class="details custom-block"><summary>Which is the best Browser for privacy? 🌐</summary><p><a href="https://www.torproject.org/" target="_blank" rel="noreferrer">Tor</a> &gt; <a href="https://mullvad.net/en/browser" target="_blank" rel="noreferrer">Mullvad</a> &gt; <a href="https://librewolf.net/" target="_blank" rel="noreferrer">LibreWolf</a> &gt; <a href="https://brave.com/" target="_blank" rel="noreferrer">Brave</a> &gt; <a href="https://www.mozilla.org/en-US/firefox/" target="_blank" rel="noreferrer">Firefox</a></p><p>But again with greater security comes greater inconveniences, its always smart to keep at least two browsers balancing security and convenience.</p><p>I recommend Brave as primary browser and Firefox with recommended extensions for normie users.</p><p>Avoid browsers like Opera, not recommended even for normal usage, <a href="https://www.kuketz-blog.de/opera-datensendeverhalten-desktop-version-browser-check-teil13" target="_blank" rel="noreferrer">very</a> <a href="https://rentry.co/operagx" target="_blank" rel="noreferrer">bad</a> privacy policies, besides <a href="https://www.androidpolice.com/2020/01/21/opera-predatory-loans" target="_blank" rel="noreferrer">predatory</a> loan apps</p></details><details class="details custom-block"><summary>Which is the best Antivirus? 🛡️</summary><p>None.</p><p>You don&#39;t need any antivirus, the built-in windows defender should suffice. Make sure you don&#39;t download stupid crap from internet, staying vigilant is very important.</p><p>However if you still feel like you want an antivirus, <a href="https://www.malwarebytes.com/" target="_blank" rel="noreferrer">malwarebytes</a> is the one I can vouch for</p></details><details class="details custom-block"><summary>I dont need Edge browser, should I uninstall it?</summary><p>Yes! There&#39;s no point of keeping it, if you dont ever plan to use it.</p><p>Click <a href="https://gist.github.com/ave9858/c3451d9f452389ac7607c99d45edecc6" target="_blank" rel="noreferrer">here</a> to uninstall edge</p><p>Make sure you set some other browser as default before deleting this.</p></details><details class="details custom-block"><summary>How can I make my download faster</summary><p>Some websites impose file transfer limits for a single thread, thereby restricting download speeds. Download managers overcome this limitation by leveraging multiple threads for downloading, resulting in faster download speeds.</p><p>Using a <a href="https://abdownloadmanager.com/" target="_blank" rel="noreferrer">download manager</a> can speed up your download</p></details>',6)])])}const u=a(o,[["render",n]]);export{f as __pageData,u as default};
